 public async Task<ApiResponse<PagedResult<TradeDossierRow>>>GetPagedAsync(TradeDossierQuery q,CancellationToken ct){var x=db.TradeDossiers.AsNoTracking().Include(v=>v.BusinessPartner).AsQueryable();if(q.Direction.HasValue)x=x.Where(v=>v.Direction==q.Direction);if(q.Status.HasValue)x=x.Where(v=>v.Status==q.Status);if(q.BranchId.HasValue)x=x.Where(v=>v.BranchId==q.BranchId);if(q.BusinessPartnerId.HasValue)x=x.Where(v=>v.BusinessPartnerId==q.BusinessPartnerId);if(q.CustomsWaitingOnly)x=x.Where(v=>v.Status>=TradeDossierStatus.Arrived&&v.Status<TradeDossierStatus.Released);if(!string.IsNullOrWhiteSpace(q.Search)){var s=q.Search.Trim();x=x.Where(v=>v.DossierNumber.Contains(s)||v.BusinessPartner.Name.Contains(s)||(v.CustomsOfficeCode!=null&&v.CustomsOfficeCode.Contains(s)));}x=x.ApplyPagedFilters(q);var total=await x.CountAsync(ct);var rows=await x.ApplyPagedSort(q,nameof(TradeDossier.OpenDate),true).ThenByDescending(v=>v.Id).Skip((q.NormalizedPageNumber-1)*q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v=>new TradeDossierRow(v.Id,v.DossierNumber,v.Direction.ToString(),v.OperationType.ToString(),v.Status.ToString(),v.BusinessPartnerId,v.BusinessPartner.Name,v.CurrencyCode,v.IncotermCode,v.OpenDate,v.EstimatedArrivalDate,v.ActualArrivalDate,v.Declarations.Count,v.Links.Count,v.Status>=TradeDossierStatus.Arrived&&v.Status<TradeDossierStatus.Released?(double?)EF.Functions.DateDiffMinute(v.ActualArrivalDate.HasValue?v.ActualArrivalDate.Value.ToDateTime(TimeOnly.MinValue):v.CreatedAt,DateTime.UtcNow)/60d:null)).ToListAsync(ct);return ApiResponse<PagedResult<TradeDossierRow>>.Ok(new(rows,q.NormalizedPageNumber,q.NormalizedPageSize,total));}
 public async Task<ApiResponse<object>>GetDetailAsync(long id,CancellationToken ct){var d=await db.TradeDossiers.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.DossierNumber,Direction=x.Direction.ToString(),OperationType=x.OperationType.ToString(),Status=x.Status.ToString(),x.BranchId,x.BusinessPartnerId,BusinessPartner=x.BusinessPartner.Name,x.CustomsBrokerId,x.CarrierId,x.CurrencyId,x.CurrencyCode,x.IncotermCode,x.PaymentMethodCode,x.DeliveryMethodCode,x.CustomsOfficeCode,x.BondedWarehouseId,TransportMode=x.TransportMode.ToString(),x.MasterTransportDocumentNumber,x.HouseTransportDocumentNumber,x.ContainerNumber,x.VehicleOrVoyageNumber,x.PortOfLoadingCode,x.PortOfDischargeCode,x.CountryOfDispatchCode,x.OpenDate,x.EstimatedArrivalDate,x.ActualArrivalDate,x.ReleasedAt,x.ClosedAt,x.Notes}).FirstOrDefaultAsync(ct);if(d is null)return ApiResponse<object>.Error("Trade dossier not found.",404);var declarations=await db.CustomsDeclarations.AsNoTracking().Where(x=>x.TradeDossierId==id).OrderByDescending(x=>x.DeclarationDate).Select(x=>new{x.Id,DeclarationType=x.DeclarationType.ToString(),Status=x.Status.ToString(),x.DeclarationNumber,x.DeclarationDate,x.RegimeCode,x.CustomsOfficeCode,x.BondedWarehouseId,x.CustomsExchangeRate,x.GuaranteeReference,x.RegistrationNumber,InspectionChannel=x.InspectionChannel.ToString(),x.TotalTaxes,x.RegisteredAt,x.ReleasedAt,x.ClosedAt,LineCount=x.Lines.Count,Quantity=x.Lines.Sum(l=>l.Quantity),ReleasedQuantity=x.Lines.Sum(l=>l.ReleasedQuantity)}).ToListAsync(ct);var declarationHistory=await db.CustomsDeclarationStatusHistory.AsNoTracking().Where(x=>x.CustomsDeclaration.TradeDossierId==id).OrderByDescending(x=>x.OccurredAt).Select(x=>new{x.Id,x.CustomsDeclarationId,FromStatus=x.FromStatus.ToString(),ToStatus=x.ToStatus.ToString(),x.OccurredAt,x.ReasonCode,x.Notes}).ToListAsync(ct);var history=await db.TradeDossierStatusHistory.AsNoTracking().Where(x=>x.TradeDossierId==id).OrderByDescending(x=>x.OccurredAt).Select(x=>new{x.Id,FromStatus=x.FromStatus.ToString(),ToStatus=x.ToStatus.ToString(),x.ReasonCode,x.OccurredAt,x.PlannedAt,x.ResponsiblePartnerId,x.Notes}).ToListAsync(ct);var links=await db.TradeDocumentLinks.AsNoTracking().Where(x=>x.TradeDossierId==id).OrderByDescending(x=>x.CreatedAt).Select(x=>new{x.Id,LinkType=x.LinkType.ToString(),x.SourceId,x.SourceLineId,x.LinkedQuantity,x.ReferenceNumber,x.CreatedAt}).ToListAsync(ct);var attachments=await db.TradeAttachments.AsNoTracking().Where(x=>x.TradeDossierId==id).OrderByDescending(x=>x.CreatedAt).Select(x=>new{x.Id,AttachmentType=x.AttachmentType.ToString(),x.CustomsDeclarationId,x.DocumentNumber,x.DocumentDate,x.OriginalFileName,x.ContentType,x.FileSize,x.CreatedAt,DownloadUrl=$"/api/trade-dossiers/{id}/attachments/{x.Id}"}).ToListAsync(ct);return ApiResponse<object>.Ok(new{dossier=d,declarations,declarationHistory,history,links,attachments,customsWaitingHours=d.Status is nameof(TradeDossierStatus.Released) or nameof(TradeDossierStatus.Completed) or nameof(TradeDossierStatus.Closed)?null:(double?)(DateTime.UtcNow-(d.ActualArrivalDate?.ToDateTime(TimeOnly.MinValue)??DateTime.UtcNow)).TotalHours});}
 public async Task<ApiResponse<object>>CreateAsync(CreateTradeDossierRequest r,CancellationToken ct){var no=r.DossierNumber.Trim().ToUpperInvariant();if(string.IsNullOrWhiteSpace(no)||await db.TradeDossiers.AnyAsync(x=>x.DossierNumber==no,ct))return ApiResponse<object>.Error("Dossier number is required and must be unique.",409);if(!await db.BusinessPartners.AnyAsync(x=>x.Id==r.BusinessPartnerId&&x.IsActive,ct))return ApiResponse<object>.Error("Business partner not found.",404);var currency=await db.Set<Currency>().AsNoTracking().FirstOrDefaultAsync(x=>x.Id==r.CurrencyId&&x.IsActive,ct);if(currency is null)return ApiResponse<object>.Error("An active defined currency is required.",400);var e=new TradeDossier{DossierNumber=no,Direction=r.Direction,OperationType=r.OperationType,Status=TradeDossierStatus.Draft,BranchId=r.BranchId,BusinessPartnerId=r.BusinessPartnerId,CustomsBrokerId=r.CustomsBrokerId,CarrierId=r.CarrierId,CurrencyId=currency.Id,CurrencyCode=currency.IsoCode,IncotermCode=r.IncotermCode.Trim().ToUpperInvariant(),PaymentMethodCode=r.PaymentMethodCode?.Trim().ToUpperInvariant(),DeliveryMethodCode=r.DeliveryMethodCode?.Trim().ToUpperInvariant(),CustomsOfficeCode=r.CustomsOfficeCode?.Trim().ToUpperInvariant(),BondedWarehouseId=r.BondedWarehouseId,TransportMode=r.TransportMode,MasterTransportDocumentNumber=r.MasterTransportDocumentNumber?.Trim(),HouseTransportDocumentNumber=r.HouseTransportDocumentNumber?.Trim(),ContainerNumber=r.ContainerNumber?.Trim().ToUpperInvariant(),VehicleOrVoyageNumber=r.VehicleOrVoyageNumber?.Trim(),PortOfLoadingCode=r.PortOfLoadingCode?.Trim().ToUpperInvariant(),PortOfDischargeCode=r.PortOfDischargeCode?.Trim().ToUpperInvariant(),CountryOfDispatchCode=r.CountryOfDispatchCode?.Trim().ToUpperInvariant(),OpenDate=r.OpenDate,EstimatedArrivalDate=r.EstimatedArrivalDate,Notes=r.Notes};db.TradeDossiers.Add(e);await db.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id,e.DossierNumber,e.Status,e.CurrencyId,e.CurrencyCode});}
 public async Task<ApiResponse<object>>ChangeStatusAsync(long id,ChangeTradeStatusRequest r,CancellationToken ct){var d=await db.TradeDossiers.FirstOrDefaultAsync(x=>x.Id==id,ct);if(d is null)return ApiResponse<object>.Error("Trade dossier not found.",404);if(!Allowed.TryGetValue(d.Status,out var choices)||!choices.Contains(r.Status))return ApiResponse<object>.Error($"Transition from {d.Status} to {r.Status} is not allowed.",409);var at=r.OccurredAt??DateTime.UtcNow;db.TradeDossierStatusHistory.Add(new(){TradeDossierId=id,FromStatus=d.Status,ToStatus=r.Status,ReasonCode=r.ReasonCode?.Trim().ToUpperInvariant(),OccurredAt=at,PlannedAt=r.PlannedAt,ResponsiblePartnerId=r.ResponsiblePartnerId,Notes=r.Notes});d.Status=r.Status;if(r.Status==TradeDossierStatus.Arrived)d.ActualArrivalDate=DateOnly.FromDateTime(at);if(r.Status is TradeDossierStatus.Released or TradeDossierStatus.ExitAuthorized)d.ReleasedAt=at;if(r.Status==TradeDossierStatus.Closed)d.ClosedAt=at;await db.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{d.Id,d.Status});}
 public async Task<ApiResponse<object>>AddDeclarationAsync(long id,CreateCustomsDeclarationRequest r,CancellationToken ct){var d=await db.TradeDossiers.FirstOrDefaultAsync(x=>x.Id==id,ct);if(d is null)return ApiResponse<object>.Error("Trade dossier not found.",404);if(d.Status is TradeDossierStatus.Closed or TradeDossierStatus.Cancelled)return ApiResponse<object>.Error("Closed or cancelled dossier cannot be changed.",409);if(r.CustomsExchangeRate<=0||r.TotalTaxes<0||r.Lines.Count==0||r.Lines.Any(x=>x.Quantity<=0||x.ReleasedQuantityInvalid()))return ApiResponse<object>.Error("Declaration requires a positive customs exchange rate, non-negative taxes and valid lines.",400);var number=r.DeclarationNumber.Trim().ToUpperInvariant();if(await db.CustomsDeclarations.AnyAsync(x=>x.DeclarationNumber==number,ct))return ApiResponse<object>.Error("Declaration number already exists.",409);var e=new CustomsDeclaration{TradeDossierId=id,DeclarationType=r.DeclarationType,Status=CustomsDeclarationStatus.Registered,DeclarationNumber=number,DeclarationDate=r.DeclarationDate,RegimeCode=r.RegimeCode.Trim().ToUpperInvariant(),CustomsOfficeCode=r.CustomsOfficeCode.Trim().ToUpperInvariant(),BondedWarehouseId=r.BondedWarehouseId,CustomsExchangeRate=r.CustomsExchangeRate,GuaranteeReference=r.GuaranteeReference?.Trim(),RegistrationNumber=r.RegistrationNumber?.Trim().ToUpperInvariant(),InspectionChannel=r.InspectionChannel,TotalTaxes=r.TotalTaxes,RegisteredAt=DateTime.UtcNow,Notes=r.Notes};var n=0;foreach(var l in r.Lines)e.Lines.Add(new(){LineNumber=++n,ProductId=l.ProductId,GtipCode=l.GtipCode.Trim(),CountryOfOriginCode=l.CountryOfOriginCode?.Trim().ToUpperInvariant(),Quantity=l.Quantity,UnitId=l.UnitId,NetWeight=l.NetWeight,GrossWeight=l.GrossWeight,PackageCount=l.PackageCount,CustomsValue=l.CustomsValue,CustomsDuty=l.CustomsDuty,VatAmount=l.VatAmount});db.CustomsDeclarations.Add(e);await db.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id,e.DeclarationNumber,e.Status});}
 public async Task<ApiResponse<object>>ChangeDeclarationStatusAsync(long id,long declarationId,ChangeCustomsDeclarationStatusRequest r,CancellationToken ct){var d=await db.TradeDossiers.FirstOrDefaultAsync(x=>x.Id==id,ct);if(d is null)return ApiResponse<object>.Error("Trade dossier not found.",404);if(d.Status is TradeDossierStatus.Closed or TradeDossierStatus.Cancelled)return ApiResponse<object>.Error("Closed or cancelled dossier cannot be changed.",409);var declaration=await db.CustomsDeclarations.FirstOrDefaultAsync(x=>x.Id==declarationId&&x.TradeDossierId==id,ct);if(declaration is null)return ApiResponse<object>.Error("Customs declaration not found.",404);if(!DeclarationAllowed.TryGetValue(declaration.Status,out var choices)||!choices.Contains(r.Status))return ApiResponse<object>.Error($"Transition from {declaration.Status} to {r.Status} is not allowed.",409);var from=declaration.Status;var at=r.OccurredAt??DateTime.UtcNow;db.CustomsDeclarationStatusHistory.Add(new(){CustomsDeclarationId=declaration.Id,FromStatus=from,ToStatus=r.Status,OccurredAt=at,ReasonCode=$"STATUS_{r.Status.ToString().ToUpperInvariant()}",Notes=r.Notes});declaration.Status=r.Status;if(r.Status==CustomsDeclarationStatus.Registered)declaration.RegisteredAt=at;if(r.Status==CustomsDeclarationStatus.Released)declaration.ReleasedAt=at;if(r.Status==CustomsDeclarationStatus.Closed)declaration.ClosedAt=at;var mapped=r.Status switch{CustomsDeclarationStatus.Inspection=>TradeDossierStatus.Inspection,CustomsDeclarationStatus.TaxCalculated or CustomsDeclarationStatus.TaxPaid=>TradeDossierStatus.TaxWaiting,CustomsDeclarationStatus.ReleaseWaiting=>TradeDossierStatus.ReleaseWaiting,_=>(TradeDossierStatus?)null};if(mapped.HasValue&&d.Status!=mapped.Value){db.TradeDossierStatusHistory.Add(new(){TradeDossierId=id,FromStatus=d.Status,ToStatus=mapped.Value,ReasonCode=$"DECLARATION_{r.Status.ToString().ToUpperInvariant()}",OccurredAt=at,Notes=r.Notes});d.Status=mapped.Value;}await db.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{declaration.Id,FromStatus=from,declaration.Status,OccurredAt=at});}
 public async Task<ApiResponse<object>>LinkAsync(long id,LinkTradeDocumentRequest r,CancellationToken ct){if(!await db.TradeDossiers.AnyAsync(x=>x.Id==id,ct))return ApiResponse<object>.Error("Trade dossier not found.",404);if(await db.TradeDocumentLinks.AnyAsync(x=>x.TradeDossierId==id&&x.LinkType==r.LinkType&&x.SourceId==r.SourceId&&x.SourceLineId==r.SourceLineId,ct))return ApiResponse<object>.Error("Document is already linked.",409);var link=new TradeDocumentLink{TradeDossierId=id,LinkType=r.LinkType,SourceId=r.SourceId,SourceLineId=r.SourceLineId,LinkedQuantity=r.LinkedQuantity,ReferenceNumber=r.ReferenceNumber?.Trim()};db.TradeDocumentLinks.Add(link);await db.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{link.Id});}
 public async Task<ApiResponse<object>>ReleaseAsync(long id,ReleaseCustomsStockRequest r,CancellationToken ct){var d=await db.TradeDossiers.FirstOrDefaultAsync(x=>x.Id==id&&x.Direction==TradeDirection.Import,ct);if(d is null)return ApiResponse<object>.Error("Import trade dossier not found.",404);var declaration=await db.CustomsDeclarations.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==r.CustomsDeclarationId&&x.TradeDossierId==id,ct);if(declaration is null)return ApiResponse<object>.Error("Customs declaration not found.",404);if(declaration.Status<CustomsDeclarationStatus.TaxPaid)return ApiResponse<object>.Error("Declaration must reach tax-paid/release stage before nationalization.",409);if(r.Lines.Count==0)return ApiResponse<object>.Error("At least one release line is required.",400);await u.ExecuteInTransactionAsync(async token=>{foreach(var item in r.Lines){if(item.Quantity<=0)throw new InvalidOperationException("Release quantity must be positive.");var receiptLine=await db.GoodsReceiptLines.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==item.GoodsReceiptLineId,token)??throw new InvalidOperationException("Goods receipt line not found.");var linkExists=await db.TradeDocumentLinks.AnyAsync(x=>x.TradeDossierId==id&&x.LinkType==TradeLinkType.GoodsReceipt&&x.SourceId==receiptLine.GoodsReceiptId&&(x.SourceLineId==null||x.SourceLineId==receiptLine.Id),token);if(!linkExists)throw new InvalidOperationException("Goods receipt line is not linked to this dossier.");var receipts=await db.InventoryTransactions.AsNoTracking().Where(x=>x.DocumentType=="GoodsReceipt"&&x.DocumentLineId==receiptLine.Id&&x.Direction==InventoryMovementDirection.Receipt).ToListAsync(token);var remaining=item.Quantity;foreach(var source in receipts){if(remaining<=0)break;var balance=await db.InventoryBalances.AsNoTracking().FirstOrDefaultAsync(x=>x.ProductId==source.ProductId&&x.WarehouseId==source.WarehouseId&&x.StorageLocationId==source.StorageLocationId&&x.InventoryStatusId==source.InventoryStatusId&&x.InventoryLotId==source.InventoryLotId&&x.InventorySerialId==source.InventorySerialId,token);var move=Math.Min(remaining,balance?.PhysicalQuantity??0);if(move<=0)continue;var common=new PostInventoryLine(source.ProductId,source.UnitId,source.WarehouseId,source.StorageLocationId,source.InventoryStatusId,source.InventoryLotId,source.InventorySerialId,move,source.UnitCost,receiptLine.Id,r.Explanation);var issue=await inventory.PostAsync(new($"CUSTOMS-RELEASE-OUT:{id}:{declaration.Id}:{receiptLine.Id}:{source.Id}","CustomsRelease",id,d.DossierNumber,r.ReleaseDate,InventoryMovementType.CustomsReleaseIssue,InventoryMovementDirection.Issue,source.CurrencyCode,[common]),token);if(!issue.Success)throw new InvalidOperationException(issue.Message);if(issue.Data!.AlreadyPosted)return;var incoming=common with{StorageLocationId=item.DestinationStorageLocationId,InventoryStatusId=item.DestinationInventoryStatusId};var receipt=await inventory.PostAsync(new($"CUSTOMS-RELEASE-IN:{id}:{declaration.Id}:{receiptLine.Id}:{source.Id}","CustomsRelease",id,d.DossierNumber,r.ReleaseDate,InventoryMovementType.CustomsReleaseReceipt,InventoryMovementDirection.Receipt,source.CurrencyCode,[incoming]),token);if(!receipt.Success)throw new InvalidOperationException(receipt.Message);remaining-=move;}if(remaining>0)throw new InvalidOperationException("Insufficient customs-held inventory for release.");}db.CustomsDeclarationStatusHistory.Add(new(){CustomsDeclarationId=declaration.Id,FromStatus=declaration.Status,ToStatus=CustomsDeclarationStatus.Released,OccurredAt=r.ReleaseDate,ReasonCode="CUSTOMS_RELEASE",Notes=r.Explanation});declaration.Status=CustomsDeclarationStatus.Released;declaration.ReleasedAt=r.ReleaseDate;foreach(var line in declaration.Lines)line.ReleasedQuantity=line.Quantity;db.TradeDossierStatusHistory.Add(new(){TradeDossierId=id,FromStatus=d.Status,ToStatus=TradeDossierStatus.Released,ReasonCode="CUSTOMS_RELEASE",OccurredAt=r.ReleaseDate,Notes=r.Explanation});d.Status=TradeDossierStatus.Released;d.ReleasedAt=r.ReleaseDate;await db.SaveChangesAsync(token);},ct);return ApiResponse<object>.Ok(new{DossierId=d.Id,d.Status,DeclarationId=declaration.Id,DeclarationStatus=declaration.Status});}
